phase3.solution:
package main

import "fmt"

func main() {
    health := 45

    if health > 75 {
        fmt.Println("Healthy")
    } else if health > 40 {
        fmt.Println("Wounded")
    } else if health > 20 {
        fmt.Println("Critical")
    } else {
        fmt.Println("Dead")
    }

    if level := 5; level >= 5 {
        fmt.Println("High level")
    }
}
